                <h5>Compact Mode</h5>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
                    <label class="form-check-label" for="compactMode">Enable compact mode</label>
                </div>
            </div>
        </div>

        <div class="col-md-6">
            <h5>Live Preview</h5>
            <div class="appearance-preview @GetPreviewClass()" style="@GetPreviewStyle()">
                <div class="preview-header">
                    <strong>Preview</strong>
                </div>
                <div class="preview-body">
                    <p class="preview-text">This is how your content will look with the selected settings.</p>
                    <div class="preview-card">
                        <span class="preview-label">Theme:</span> @Theme
                    </div>
                    <div class="preview-card">
                        <span class="preview-label">Font:</span> @FontSize
                    </div>
                    <div class="preview-card">
                        <span class="preview-label">Language:</span> @Language
                    </div>
                    <div class="preview-card">
                        <span class="preview-label">Compact:</span> @(CompactMode ? "On" : "Off")
                    </div>
                </div>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(Message))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @Message
            <button type="button" class="btn-close" @onclick="() => Message = null"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
        @(IsSaving ? "Saving..." : "Save")
    </button>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private string? Message;
    private bool IsSaving;
    private bool _initialized;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private string GetPreviewClass()
    {
        var classes = new List<string>();
        if (Theme == "Dark") classes.Add("preview-dark");
        if (CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private string GetPreviewStyle()
    {
        var size = FontSize switch
        {
            "Small" => "0.85rem",
            "Large" => "1.15rem",
            _ => "1rem"
        };
        return $"font-size: {size};";
    }

    private async Task Save()
    {
        IsSaving = true;
        try
        {
            var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
            await OnSave.InvokeAsync(updated);
            Message = "Appearance saved successfully!";
        }
        finally
        {
            IsSaving = false;
        }
    }
}

