{"file_text": "@namespace sv_0ee81eb1b1a641d3a8c5ea23f393222b.Components.Pages.Settings
@using sv_0ee81eb1b1a641d3a8c5ea23f393222b.Services

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>
    <hr />

    <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

    <div class="mb-4">
        <h5>Two-Factor Authentication</h5>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@TwoFactorEnabled"
                       @onchange="e => TwoFactorEnabled = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="twoFactor">Enable 2FA</label>
            </div>
            <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                @(TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Security?.LastPasswordChange is not null)
        {
            <p class="text-muted small mt-2">
                Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }
    </div>

    <div class="mb-4">
        <h5>Active Sessions</h5>
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (Security?.Sessions is not null)
                    {
                        @foreach (var session in Security.Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => ShowRevokeDialog(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

<RevokeSessionDialog IsVisible="@_showRevokeDialog"
                     SessionId="@(_sessionToRevoke?.Id ?? "")"
                     Device="@(_sessionToRevoke?.Device ?? "")"
                     Location="@(_sessionToRevoke?.Location ?? "")"
                     OnConfirm="HandleRevoke"
                     OnCancel="() => { _showRevokeDialog = false; _sessionToRevoke = null; }" />

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string current, string newPass)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool TwoFactorEnabled;
    private string CurrentSessionId = "sess-1"; // first session is "current"
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Security is not null && !_initialized)
        {
            TwoFactorEnabled = Security.TwoFactorEnabled;
            _initialized = true;
        }
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task HandleRevoke(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private async Task HandleChangePassword((string current, string newPass) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
