+@namespace sv_0ee81eb1b1a641d3a8c5ea23f393222b.Components.Pages.Settings
+@using sv_0ee81eb1b1a641d3a8c5ea23f393222b.Services
+
+<div class="settings-section">
+    <h3>Notifications</h3>
+    <p class="text-muted">Configure how you receive notifications</p>
+    <hr />
+
+    <div class="mb-4">
+        <h5>Notification Channels</h5>
+        <div class="form-check form-switch mb-2">
+            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
+            <label class="form-check-label" for="emailNotif">Email Notifications</label>
+        </div>
+        <div class="form-check form-switch mb-2">
+            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
+            <label class="form-check-label" for="pushNotif">Push Notifications</label>
+        </div>
+        <div class="form-check form-switch mb-2">
+            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
+            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
+        </div>
+    </div>
+
+    <div class="mb-4">
+        <h5>Muted Channels</h5>
+        <p class="text-muted small">Uncheck channels you want to mute</p>
+        @foreach (var channel in AllChannels)
+        {
+            var id = $"channel-{channel}";
+            var isMuted = MutedChannels.Contains(channel);
+            <div class="form-check mb-1">
+                <input class="form-check-input" type="checkbox" id="@id"
+                       checked="@(!isMuted)"
+                       @onchange="e => ToggleChannel(channel, e)" />
+                <label class="form-check-label" for="@id">
+                    #@channel
+                    @if (isMuted)
+                    {
+                        <span class="badge bg-secondary ms-1">muted</span>
+                    }
+                </label>
+            </div>
+        }
+    </div>
+
+    @if (!string.IsNullOrEmpty(Message))
+    {
+        <div class="alert alert-success alert-dismissible fade show" role="alert">
+            @Message
+            <button type="button" class="btn-close" @onclick="() => Message = null"></button>
+        </div>
+    }
+
+    <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
+        @(IsSaving ? "Saving..." : "Save Preferences")
+    </button>
+</div>
+
+@code {
+    [Parameter] public NotificationPrefs? Prefs { get; set; }
+    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
+
+    private bool EmailNotifications;
+    private bool PushNotifications;
+    private bool WeeklyDigest;
+    private List<string> MutedChannels = [];
+    private string? Message;
+    private bool IsSaving;
+
+    private static readonly List<string> AllChannels = ["general", "announcements", "marketing", "engineering", "design", "support"];
+
+    private bool _initialized;
+
+    protected override void OnParametersSet()
+    {
+        if (Prefs is not null && !_initialized)
+        {
+            EmailNotifications = Prefs.EmailNotifications;
+            PushNotifications = Prefs.PushNotifications;
+            WeeklyDigest = Prefs.WeeklyDigest;
+            MutedChannels = [.. Prefs.MutedChannels];
+            _initialized = true;
+        }
+    }
+
+    private void ToggleChannel(string channel, ChangeEventArgs e)
+    {
+        var isChecked = (bool)(e.Value ?? false);
+        if (isChecked)
+            MutedChannels.Remove(channel);
+        else if (!MutedChannels.Contains(channel))
+            MutedChannels.Add(channel);
+    }
+
+    private async Task Save()
+    {
+        IsSaving = true;
+        try
+        {
+            var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
+            await OnSave.InvokeAsync(updated);
+            Message = "Preferences saved successfully!";
+        }
+        finally
+        {
+            IsSaving = false;
+        }
+    }
+}
