@namespace sv_0ee81eb1b1a641d3a8c5ea23f393222b.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="sidebar-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_0ee81eb1b1a641d3a8c5ea23f393222b.Components.Pages.Settings
@using sv_0ee81eb1b1a641d3a8c5ea23f393222b.Services

<div class="settings-section">
    <h3>Profile</h3>
    <p class="text-muted">Manage your personal information</p>
    <hr />

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <img src="@AvatarUrl" alt="Avatar" class="rounded-circle mb-2" width="120" height="120" />
                <div class="mb-2">
                    <label class="form-label">Avatar URL</label>
                    <input type="text" class="form-control form-control-sm" @bind="AvatarUrl" />
                </div>
            </div>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(Message))
    {
        <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-2" role="alert">
            @Message
            <button type="button" class="btn-close" @onclick="() => Message = null"></button>
        </div>
    }

    <div class="mt-3">
        <button class="btn btn-primary me-2" @onclick="Save" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string Bio = "";
    private string AvatarUrl = "";
    private string? Message;
    private bool IsError;
    private bool IsSaving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        Bio = profile.Bio;
        AvatarUrl = profile.AvatarUrl;
    }

    private async Task Save()
    {
        IsSaving = true;
        IsError = false;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            Message = "Profile saved successfully!";
        }
        catch
        {
            Message = "Failed to save profile.";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
            Message = null;
        }
    }
}

