+        if (CompactMode) classes.Add("preview-compact");
+        return string.Join(" ", classes);
+    }
+
+    private string GetPreviewStyle()
+    {
+        var size = FontSize switch
+        {
+            "Small" => "0.85rem",
+            "Large" => "1.15rem",
+            _ => "1rem"
+        };
+        return $"font-size: {size};";
