.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 500px;
}

/* Sidebar */
.settings-sidebar {
    min-width: 200px;
    max-width: 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.sidebar-title {
    padding: 0.5rem 0.75rem;
    margin-bottom: 0.5rem;
    font-weight: 600;
    color: #495057;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 0.75rem;
    border-radius: 0.375rem;
    color: #495057;
    background: none;
    border: none;
    width: 100%;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s;
}

.settings-sidebar .nav-link:hover {
    background-color: #f0f0f0;
}

.settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* Appearance preview */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.3s ease;
    background: #fff;
    color: #212529;
}

.appearance-preview.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.appearance-preview.preview-compact .preview-body {
    padding: 0.5rem;
}

.appearance-preview.preview-compact .preview-card {
    padding: 0.25rem 0.5rem;
    margin-bottom: 0.25rem;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: rgba(0, 0, 0, 0.03);
}

.preview-dark .preview-header {
    border-bottom-color: #444;
    background: rgba(255, 255, 255, 0.05);
}

.preview-body {
    padding: 1rem;
}

.preview-text {
    margin-bottom: 0.75rem;
}

.preview-card {
    padding: 0.5rem 0.75rem;
    margin-bottom: 0.5rem;
    border-radius: 0.25rem;
    background: rgba(0, 0, 0, 0.04);
}

.preview-dark .preview-card {
    background: rgba(255, 255, 255, 0.08);
}

.preview-label {
    font-weight: 600;
}

